import { HighlightStyle } from '@codemirror/language';
import type { NodePropSource } from '@lezer/common';
import { styleTags, tags } from '@lezer/highlight';

import { operator } from '../FilterField.sty.js';

// The codemirror highlighter can only target leaf nodes for highlighting, meaning
// it will add wrapping spans with the given classes for styling.
// Since the FilterKey and FilterValue have nested tokens (Identifier), we can't use
// the highlighter but have to create decorations for each.
/**
 * @internal
 */
export const filterFieldStyleTags: NodePropSource = styleTags({
  ComparisonOperator: tags.compareOperator,
  ExistsOperator: tags.compareOperator,
  InclusionOperator: tags.compareOperator,
  LogicalOperator: tags.logicOperator,
});

/** @internal */
export const filterFieldHighlighter = HighlightStyle.define([
  { tag: tags.compareOperator, class: operator },
  { tag: tags.logicOperator, class: operator },
]);
